const logicItem = $('Get BTC Logic Document').first().json;
const marketItem = $('Build BTC Input Pack').first().json;

let logicDocument = logicItem.content || '';

if (logicItem.encoding === 'base64') {
  logicDocument = Buffer.from(logicDocument, 'base64').toString('utf8');
}

return [
  {
    json: {
      logic_document: logicDocument,
      market_snapshot: marketItem
    }
  }
];

const openAiItem = $input.first().json;

let text =
  openAiItem.output?.[0]?.content?.[0]?.text ||
  openAiItem.text ||
  openAiItem.message ||
  '';

if (!text) {
  throw new Error('No OpenAI text output found');
}

text = String(text)
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let report;
try {
  report = JSON.parse(text);
} catch (error) {
  throw new Error(`Failed to parse OpenAI JSON output: ${error.message}`);
}

const combined = $('Combine md & market snapshot').first().json || {};
const marketSnapshot = combined.market_snapshot || combined || {};

function pct(value) {
  if (value === null || value === undefined || value === '') return null;
  if (typeof value === 'number') return Number.isFinite(value) ? value : null;

  const match = String(value).match(/-?\d+(\.\d+)?/);
  return match ? Number(match[0]) : null;
}

function reasonFor(tf) {
  return (
    report[`reason_${tf}`] ||
    report[`${tf}_reason`] ||
    report.reasoning_summary ||
    ''
  );
}

const snapshotId =
  marketSnapshot.snapshot_id ||
  marketSnapshot.id ||
  null;

const snapshotDate =
  marketSnapshot.snapshot_date ||
  new Date().toISOString().slice(0, 10);

const runTimeEt =
  marketSnapshot.run_time_et ||
  new Date().toISOString();

const availableInputs =
  marketSnapshot.available_inputs ||
  marketSnapshot.market_inputs ||
  {};

const missingInputs = Array.from(new Set([
  ...(Array.isArray(report.missing_inputs) ? report.missing_inputs : []),
  ...(Array.isArray(marketSnapshot.missing_inputs) ? marketSnapshot.missing_inputs : []),
  ...(Array.isArray(marketSnapshot.data_quality?.missing) ? marketSnapshot.data_quality.missing : [])
]));

const warnings = Array.from(new Set([
  ...(Array.isArray(report.risk_flags) ? report.risk_flags : []),
  ...(Array.isArray(report.warnings) ? report.warnings : [])
]));

const createdAt = new Date().toISOString();

return [
  {
    json: {
      snapshot_id: snapshotId,
      agent_name: 'BTC',
      layer: 1,
      run_time_et: runTimeEt,
      snapshot_date: snapshotDate,
      market_inputs: availableInputs,

      call_24h_direction: report.direction_24h || null,
      call_24h_conviction: pct(report.conviction_24h),
      call_24h_reason: reasonFor('24h'),

      call_3d_direction: report.direction_3_day || null,
      call_3d_conviction: pct(report.conviction_3_day),
      call_3d_reason: reasonFor('3d'),

      call_current_week_direction: report.direction_current_week || null,
      call_current_week_conviction: pct(report.conviction_current_week),
      call_current_week_reason: reasonFor('current_week'),

      call_next_week_direction: report.direction_next_week || null,
      call_next_week_conviction: pct(report.conviction_next_week),
      call_next_week_reason: reasonFor('next_week'),

      call_current_month_direction: report.direction_current_month || null,
      call_current_month_conviction: pct(report.conviction_current_month),
      call_current_month_reason: reasonFor('current_month'),

      direction_24h: report.direction_24h || null,
      conviction_24h: pct(report.conviction_24h),

      direction_3_day: report.direction_3_day || null,
      conviction_3_day: pct(report.conviction_3_day),

      direction_current_week: report.direction_current_week || null,
      conviction_current_week: pct(report.conviction_current_week),

      direction_next_week: report.direction_next_week || null,
      conviction_next_week: pct(report.conviction_next_week),

      direction_current_month: report.direction_current_month || null,
      conviction_current_month: pct(report.conviction_current_month),

      factor_breakdown: report.factor_breakdown || {},
      conviction_model: report.conviction_model || null,
      weighted_score: report.weighted_score || null,
      timeframe_models: report.timeframe_models || null,

      warnings,
      risk_flags: warnings,
      missing_inputs: missingInputs,

      full_output: {
        ...report,
        created_at: createdAt,
        missing_inputs: missingInputs,
        risk_flags: warnings
      },

      raw_agent_output: report,

      logic_document: 'agent_btc_direction.md',
      logic_document_version: report.logic_document_version || '2.0_weighted_engine',
      reasoning_summary: report.reasoning_summary || '',

      score_bullish: report.score_bullish ?? null,
      score_bearish: report.score_bearish ?? null,
      score_neutral: report.score_neutral ?? null,

      created_at: createdAt
    }
  }
];

const item = $input.first().json;
const inputs = item.market_inputs || {};

function n(v) {
  if (v === null || v === undefined || v === '') return null;
  const x = Number(v);
  return Number.isFinite(x) ? x : null;
}

function makeFactor(signal, evidence, reason) {
  return { signal, evidence, reason };
}

function isWeekendRisk() {
  const day = new Date().getUTCDay();
  return day === 0 || day === 6 || day === 5;
}

function signalFromDelta(value, upThreshold, downThreshold, bullishReason, bearishReason, neutralReason, label, invert = false) {
  const d = n(value);
  if (d === null) return makeFactor("NEUTRAL", `Missing ${label}`, "Missing input");

  if (!invert) {
    if (d >= upThreshold) return makeFactor("BULLISH", `${label} ${d}`, bullishReason);
    if (d <= downThreshold) return makeFactor("BEARISH", `${label} ${d}`, bearishReason);
  } else {
    if (d >= upThreshold) return makeFactor("BEARISH", `${label} ${d}`, bearishReason);
    if (d <= downThreshold) return makeFactor("BULLISH", `${label} ${d}`, bullishReason);
  }

  return makeFactor("NEUTRAL", `${label} ${d}`, neutralReason);
}

const TIMEFRAME_WEIGHTS = {
  "24h": { F1: 16, F2: 14, F3: 10, F4: 10, F5: 16, F6: 14, F7: 6, F8: 8, F9: 3, F10: 3 },
  "3d": { F1: 12, F2: 15, F3: 14, F4: 12, F5: 14, F6: 12, F7: 7, F8: 8, F9: 4, F10: 2 },
  "current_week": { F1: 10, F2: 15, F3: 16, F4: 13, F5: 13, F6: 10, F7: 6, F8: 9, F9: 5, F10: 3 },
  "next_week": { F1: 6, F2: 14, F3: 18, F4: 16, F5: 10, F6: 7, F7: 5, F8: 11, F9: 9, F10: 4 },
  "current_month": { F1: 7, F2: 14, F3: 18, F4: 17, F5: 9, F6: 6, F7: 4, F8: 12, F9: 9, F10: 4 }
};

function selectedInputs(tf) {
  const use20d = tf === "next_week" || tf === "current_month";

  return {
    btcDelta: tf === "24h" ? inputs.btc_d1_pct : use20d ? inputs.btc_d20_pct : inputs.btc_d5_pct,
    dxyDelta: tf === "24h" ? inputs.dxy_d1 : use20d ? inputs.dxy_d20 : inputs.dxy_d5,
    realYieldDelta: use20d ? inputs.us_10y_real_yield_d20_bps : inputs.us_10y_real_yield_d5_bps,
    nqDelta: tf === "24h" ? inputs.nq_d1_pct : use20d ? inputs.nq_d20_pct : inputs.nq_d5_pct,
    etfFlow: tf === "24h" ? inputs.btc_etf_net_flow_1d_usd : use20d ? inputs.btc_etf_net_flow_20d_usd : inputs.btc_etf_net_flow_5d_usd,
    stablecoinDelta: use20d ? inputs.stablecoin_supply_d20_pct : inputs.stablecoin_supply_d5_pct,
    dominanceDelta: use20d ? inputs.btc_dominance_d20 : inputs.btc_dominance_d5,
    totalCryptoMcapDelta: use20d ? inputs.total_crypto_market_cap_d20_pct : inputs.total_crypto_market_cap_d5_pct
  };
}

function factorSignals(tf) {
  const s = selectedInputs(tf);
  const vix = n(inputs.vix_level);
  const vixD5 = n(inputs.vix_d5);
  const fed = String(inputs.fed_bias || "").toLowerCase();
  const fearGreed = n(inputs.crypto_fear_greed);

  const signals = {};

  signals.F1 = signalFromDelta(
    s.btcDelta, 3, -3,
    "BTC own trend is above noise threshold and supports upside pressure",
    "BTC own trend is below noise threshold and confirms downside pressure",
    "BTC move is inside normal noise threshold",
    tf === "24h" ? "BTC 1d %" : (tf === "next_week" || tf === "current_month") ? "BTC 20d %" : "BTC 5d %"
  );

  signals.F2 = signalFromDelta(
    s.dxyDelta, tf === "24h" ? 0.15 : 0.3, tf === "24h" ? -0.15 : -0.3,
    "DXY weakness supports BTC/USD",
    "DXY strength pressures BTC/USD",
    "DXY move below threshold",
    tf === "24h" ? "DXY 1d %" : (tf === "next_week" || tf === "current_month") ? "DXY 20d %" : "DXY 5d %",
    true
  );

  signals.F3 = signalFromDelta(
    s.realYieldDelta, 5, -5,
    "Falling real yields reduce BTC opportunity-cost pressure",
    "Rising real yields tighten financial conditions and pressure BTC",
    "Real yield move below threshold",
    (tf === "next_week" || tf === "current_month") ? "Real yield 20d bps" : "Real yield 5d bps",
    true
  );

  signals.F4 = (() => {
    if (!fed || fed === "unknown") return makeFactor("NEUTRAL", "Fed bias unknown", "Missing input");
    if (fed.includes("dovish")) return makeFactor("BULLISH", `Fed bias ${fed}`, "Dovish Fed supports BTC through easier liquidity expectations");
    if (fed.includes("hawkish")) return makeFactor("BEARISH", `Fed bias ${fed}`, "Hawkish Fed pressures BTC through tighter liquidity expectations");
    return makeFactor("NEUTRAL", `Fed bias ${fed}`, "No clear Fed liquidity impulse");
  })();

  signals.F5 = (() => {
    if (vix === null) return makeFactor("NEUTRAL", "Missing VIX", "Missing input");
    if (vix > 30) return makeFactor("BEARISH", `VIX ${vix}`, "VIX above 30 signals BTC liquidation-risk regime");
    if (vix > 22) return makeFactor("BEARISH", `VIX ${vix}`, "Risk-off regime pressures BTC");
    if (vix < 16) return makeFactor("BULLISH", `VIX ${vix}`, "Low VIX supports risk appetite and BTC");
    if (vixD5 !== null && vixD5 > 2) return makeFactor("BEARISH", `VIX ${vix}, VIX d5 ${vixD5}`, "VIX rising materially increases BTC risk pressure");
    if (vixD5 !== null && vixD5 < -2) return makeFactor("BULLISH", `VIX ${vix}, VIX d5 ${vixD5}`, "VIX falling materially supports risk appetite");
    return makeFactor("NEUTRAL", `VIX ${vix}`, "Risk regime neutral");
  })();

  signals.F6 = signalFromDelta(
    s.nqDelta, 0.2, -0.2,
    "NQ strength confirms high-beta risk appetite for BTC",
    "NQ weakness confirms high-beta risk pressure on BTC",
    "NQ move below threshold",
    tf === "24h" ? "NQ 1d %" : (tf === "next_week" || tf === "current_month") ? "NQ 20d %" : "NQ 5d %"
  );

  signals.F7 = (() => {
    const ev = inputs.latest_us_event;
    const text = JSON.stringify(ev || {}).toLowerCase();

    if (!ev) return makeFactor("NEUTRAL", "No recent US event", "No confirmed surprise");

    const positive = text.includes("bullish") || text.includes("positive") || text.includes("beat");
    const negative = text.includes("bearish") || text.includes("negative") || text.includes("miss");

    if (positive && fed.includes("hawkish")) return makeFactor("BEARISH", JSON.stringify(ev), "Positive US surprise in hawkish Fed regime increases tightening pressure on BTC");
    if (positive) return makeFactor("BULLISH", JSON.stringify(ev), "Positive US surprise supports growth/risk appetite without clear tightening override");
    if (negative && fed.includes("hawkish")) return makeFactor("BULLISH", JSON.stringify(ev), "Negative US surprise may reduce tightening pressure and support BTC relief");
    if (negative) return makeFactor("BEARISH", JSON.stringify(ev), "Negative US surprise raises growth-risk pressure on BTC");

    return makeFactor("NEUTRAL", JSON.stringify(ev), "No clear BTC surprise impulse");
  })();

  signals.F8 = (() => {
    const flow = n(s.etfFlow);
    if (flow === null) return makeFactor("NEUTRAL", "Missing BTC ETF flow", "Missing or disabled input");
    if (flow > 0) return makeFactor("BULLISH", `ETF flow ${flow}`, "Confirmed BTC ETF net inflow supports BTC demand");
    if (flow < 0) return makeFactor("BEARISH", `ETF flow ${flow}`, "Confirmed BTC ETF net outflow pressures BTC demand");
    return makeFactor("NEUTRAL", `ETF flow ${flow}`, "ETF flow flat");
  })();

  signals.F9 = (() => {
    const stable = n(s.stablecoinDelta);
    const mcap = n(s.totalCryptoMcapDelta);

    if (stable !== null) {
      if (stable > 0.3) return makeFactor("BULLISH", `Stablecoin supply delta ${stable}%`, "Stablecoin supply expansion supports crypto liquidity");
      if (stable < -0.3) return makeFactor("BEARISH", `Stablecoin supply delta ${stable}%`, "Stablecoin supply contraction pressures crypto liquidity");
      return makeFactor("NEUTRAL", `Stablecoin supply delta ${stable}%`, "Stablecoin liquidity flat");
    }

    if (mcap !== null) {
      if (mcap > 1) return makeFactor("BULLISH", `Total crypto market cap delta ${mcap}%`, "Total crypto market cap expansion supports crypto liquidity");
      if (mcap < -1) return makeFactor("BEARISH", `Total crypto market cap delta ${mcap}%`, "Total crypto market cap contraction pressures crypto liquidity");
      return makeFactor("NEUTRAL", `Total crypto market cap delta ${mcap}%`, "Crypto market cap move below threshold");
    }

    return makeFactor("NEUTRAL", "Missing stablecoin and crypto market cap deltas", "Missing input");
  })();

  signals.F10 = (() => {
    const dom = n(inputs.btc_dominance);
    const domDelta = n(s.dominanceDelta);
    const btcDelta = n(s.btcDelta);

    if (dom === null && fearGreed === null) return makeFactor("NEUTRAL", "Missing BTC dominance and fear/greed", "Missing input");

    if (domDelta !== null && btcDelta !== null) {
      if (domDelta > 0 && btcDelta > 3) return makeFactor("BULLISH", `BTC dominance delta ${domDelta}, BTC delta ${btcDelta}%`, "BTC dominance rising with BTC price suggests BTC-led accumulation");
      if (domDelta < 0 && btcDelta < -3) return makeFactor("BEARISH", `BTC dominance delta ${domDelta}, BTC delta ${btcDelta}%`, "BTC dominance falling while BTC price weakens suggests BTC underperformance");
    }

    if (fearGreed !== null) {
      if (fearGreed <= 20 && btcDelta !== null && btcDelta > -3) return makeFactor("BULLISH", `Fear/Greed ${fearGreed}, BTC delta ${btcDelta}%`, "Extreme fear with stabilising BTC can support contrarian bullish pressure");
      if (fearGreed >= 80 && btcDelta !== null && btcDelta < 3) return makeFactor("BEARISH", `Fear/Greed ${fearGreed}, BTC delta ${btcDelta}%`, "Extreme greed with weakening BTC warns of exhaustion");
      return makeFactor("NEUTRAL", `Fear/Greed ${fearGreed}`, "Sentiment alone is not enough to drive BTC factor");
    }

    return makeFactor("NEUTRAL", `BTC dominance ${dom}`, "No clear BTC structure signal");
  })();

  return signals;
}

function factorName(id) {
  return {
    F1: "BTC Own Price Delta",
    F2: "DXY / USD Pressure",
    F3: "US 10Y Real Yield Delta",
    F4: "Fed Bias / Policy Liquidity",
    F5: "VIX Level and Risk Regime",
    F6: "NQ / High-Beta Risk Confirmation",
    F7: "US Economic Surprise Direction",
    F8: "BTC ETF / Institutional Flow",
    F9: "Stablecoin / Crypto Liquidity",
    F10: "BTC Dominance / Crypto Structure"
  }[id] || id;
}

function scoreTimeframe(tf) {
  const weights = TIMEFRAME_WEIGHTS[tf];
  const signals = factorSignals(tf);

  let bullish = 0, bearish = 0, neutral = 0;
  let bullishCount = 0, bearishCount = 0, neutralCount = 0;

  const factorBreakdown = {};
  const bullCase = [];
  const bearCase = [];
  const neutralCase = [];
  const warnings = [];

  for (const [id, sig] of Object.entries(signals)) {
    const weight = weights[id] || 0;
    const namedId = `${id} ${factorName(id)}`;

    factorBreakdown[namedId] = { ...sig, weight };

    if (sig.signal === "BULLISH") {
      bullish += weight;
      bullishCount++;
      bullCase.push(`${namedId} (${weight}): ${sig.evidence}`);
    } else if (sig.signal === "BEARISH") {
      bearish += weight;
      bearishCount++;
      bearCase.push(`${namedId} (${weight}): ${sig.evidence}`);
    } else {
      neutral += weight;
      neutralCount++;
      neutralCase.push(`${namedId} (${weight}): ${sig.evidence}`);
      if (String(sig.reason).toLowerCase().includes("missing")) {
        warnings.push(`Missing/neutral input: ${namedId}`);
      }
    }
  }

  const active = bullish + bearish;
  const bullishArgument = active > 0 ? Math.round((bullish / active) * 100) : 0;
  const bearishArgument = active > 0 ? Math.round((bearish / active) * 100) : 0;
  const neutralPct = Math.round(neutral);
  const participationPct = Math.round(active);
  const netEdge = bullishArgument - bearishArgument;

  const baseDirection = bullish > bearish ? "BULLISH" : bearish > bullish ? "BEARISH" : "NO_CLEAR_BIAS";
  const absEdge = Math.abs(netEdge);

  let direction = baseDirection === "NO_CLEAR_BIAS"
    ? "NO_CLEAR_BIAS"
    : absEdge < 20 || active < 50
      ? `${baseDirection}_LEAN`
      : baseDirection;

  if (baseDirection === "BULLISH" && n(inputs.vix_level) > 30 && bearish > 0) {
    direction = "BULLISH_LEAN";
    warnings.push("VIX above 30: bullish BTC verdict capped to lean unless all macro risk factors confirm");
  }

  if (isWeekendRisk() && tf === "24h") {
    warnings.push("WEEKEND_LIQUIDITY_RISK");
    if (direction === "BULLISH" && absEdge < 35) direction = "BULLISH_LEAN";
    if (direction === "BEARISH" && absEdge < 35) direction = "BEARISH_LEAN";
  }

  const conviction = baseDirection === "BULLISH" ? bullishArgument : baseDirection === "BEARISH" ? bearishArgument : 0;
  const strength = absEdge >= 40 ? "VERY_STRONG" : absEdge >= 25 ? "STRONG" : absEdge >= 15 ? "MODERATE" : "WEAK";
  const winningSide = baseDirection === "BULLISH" ? "BULLISH" : baseDirection === "BEARISH" ? "BEARISH" : "NONE";

  const reason =
    `${tf} BTC deterministic score: bull case ${bullish} weight, bear case ${bearish} weight, neutral evidence ${neutral} weight. ` +
    `Winning side ${winningSide}, conviction ${conviction}%, net edge ${netEdge > 0 ? "+" : ""}${netEdge}, directional participation ${participationPct}%.`;

  return {
    direction,
    conviction,
    reason,
    factor_breakdown: factorBreakdown,
    bull_case: bullCase,
    bear_case: bearCase,
    neutral_case: neutralCase,
    warnings,
    score_bullish: bullishCount,
    score_bearish: bearishCount,
    score_neutral: neutralCount,
    weighted_score: {
      bullish_weight: bullish,
      bearish_weight: bearish,
      neutral_weight: neutral,
      active_weight: active,
      weight_margin: Math.abs(bullish - bearish)
    },
    conviction_model: {
      bull_case_weight: bullish,
      bear_case_weight: bearish,
      winning_side: winningSide,
      bullish_argument_pct: bullishArgument,
      bearish_argument_pct: bearishArgument,
      neutral_evidence_pct: neutralPct,
      directional_participation_pct: participationPct,
      net_edge_pct: netEdge,
      final_conviction: conviction,
      verdict_strength: strength,
      final_conviction_logic: reason,
      weighted_edge: Math.abs(netEdge) / 100,
      raw_conviction: conviction,
      base_conviction: conviction,
      participation: participationPct,
      participation_cap: participationPct,
      conflict_penalty: 0,
      missing_input_penalty: 0,
      agreement_boost: 0
    }
  };
}

const r24h = scoreTimeframe("24h");
const r3d = scoreTimeframe("3d");
const rWeek = scoreTimeframe("current_week");
const rNextWeek = scoreTimeframe("next_week");
const rMonth = scoreTimeframe("current_month");

const allWarnings = [
  ...(Array.isArray(item.warnings) ? item.warnings : []),
  ...(r24h.warnings || []),
  ...(r3d.warnings || []),
  ...(rWeek.warnings || []),
  ...(rNextWeek.warnings || []),
  ...(rMonth.warnings || [])
];

const missingInputs = Array.isArray(item.missing_inputs) ? item.missing_inputs : [];

const output = {
  ...(item.full_output || {}),

  asset: "BTC",
  layer: "layer_1_raw",
  logic_document: "agent_btc_direction.md",
  logic_document_version: "2.0_weighted_engine",
  created_at: item.created_at || new Date().toISOString(),

  direction_24h: r24h.direction,
  conviction_24h: r24h.conviction,
  reason_24h: r24h.reason,

  direction_3_day: r3d.direction,
  conviction_3_day: r3d.conviction,
  reason_3_day: r3d.reason,

  direction_current_week: rWeek.direction,
  conviction_current_week: rWeek.conviction,
  reason_current_week: rWeek.reason,

  direction_next_week: rNextWeek.direction,
  conviction_next_week: rNextWeek.conviction,
  reason_next_week: rNextWeek.reason,

  direction_current_month: rMonth.direction,
  conviction_current_month: rMonth.conviction,
  reason_current_month: rMonth.reason,

  weighted_score: r24h.weighted_score,
  conviction_model: r24h.conviction_model,
  factor_breakdown: r24h.factor_breakdown,

  timeframe_models: {
    "24h": r24h,
    "3d": r3d,
    "current_week": rWeek,
    "next_week": rNextWeek,
    "current_month": rMonth
  },

  score_bullish: r24h.score_bullish,
  score_bearish: r24h.score_bearish,
  score_neutral: r24h.score_neutral,

  missing_inputs: missingInputs,
  risk_flags: [...new Set(allWarnings)],

  reasoning_summary:
    `BTC weighted verdicts calculated deterministically by timeframe. ` +
    `24h ${r24h.direction} ${r24h.conviction}%, ` +
    `3d ${r3d.direction} ${r3d.conviction}%, ` +
    `current week ${rWeek.direction} ${rWeek.conviction}%, ` +
    `next week ${rNextWeek.direction} ${rNextWeek.conviction}%, ` +
    `current month ${rMonth.direction} ${rMonth.conviction}%.`
};

return [{
  json: {
    snapshot_id: item.snapshot_id || null,
    agent_name: "BTC",
    layer: 1,
    run_time_et: item.run_time_et || new Date().toISOString(),
    snapshot_date: item.snapshot_date || new Date().toISOString().slice(0, 10),

    call_24h_direction: output.direction_24h,
    call_24h_conviction: output.conviction_24h,
    call_24h_reason: output.reason_24h,

    call_3d_direction: output.direction_3_day,
    call_3d_conviction: output.conviction_3_day,
    call_3d_reason: output.reason_3_day,

    call_current_week_direction: output.direction_current_week,
    call_current_week_conviction: output.conviction_current_week,
    call_current_week_reason: output.reason_current_week,

    call_next_week_direction: output.direction_next_week,
    call_next_week_conviction: output.conviction_next_week,
    call_next_week_reason: output.reason_next_week,

    call_current_month_direction: output.direction_current_month,
    call_current_month_conviction: output.conviction_current_month,
    call_current_month_reason: output.reason_current_month,

    direction_24h: output.direction_24h,
    conviction_24h: output.conviction_24h,
    direction_3_day: output.direction_3_day,
    conviction_3_day: output.conviction_3_day,
    direction_current_week: output.direction_current_week,
    conviction_current_week: output.conviction_current_week,
    direction_next_week: output.direction_next_week,
    conviction_next_week: output.conviction_next_week,
    direction_current_month: output.direction_current_month,
    conviction_current_month: output.conviction_current_month,

    factor_breakdown: output.factor_breakdown,
    conviction_model: output.conviction_model,
    weighted_score: output.weighted_score,

    warnings: output.risk_flags,

    full_output: output,
    raw_agent_output: output,

    logic_document: "agent_btc_direction.md",
    logic_document_version: "2.0_weighted_engine",
    reasoning_summary: output.reasoning_summary,

    score_bullish: output.score_bullish,
